import React from "react";
import AnimatedSection from "./AnimatedSection";

const NosotrosSection = () => (
  <AnimatedSection style={{ display: "flex", alignItems: "center", gap: "2rem", flexWrap: "wrap" }}>
    <div style={{ flex: 1, minWidth: "320px" }}>
      <h1 style={{ fontSize: "2.5rem", fontWeight: "900", marginBottom: "1rem", color: "#000000" }}>
        La historia de todos
      </h1>
      <p style={{ fontSize: "1.2rem", lineHeight: "1.8", color: "#000000" }}>
        Somos un equipo multidisciplinario que busca reflejar el impacto de las empresas bolivianas en la historia del país, mediante tecnología e innovación.
      </p>
    </div>
    <div style={{ flex: 1, minWidth: "320px", textAlign: "center" }}>
      <img
        src={require("../../assets/quien-contra-nosotros.jpg")}
        alt="Cargando..."
        style={{ maxWidth: "100%", borderRadius: "1rem", boxShadow: "0 0 15px rgba(0,0,0,0.15)" }}
      />
    </div>
  </AnimatedSection>
);

export default NosotrosSection;
